<?php require_once __DIR__.'/license_manager.php';require_once __DIR__.'/integrity_checker.php';$m=new LicenseManager();$v=$m->validateLicense();if(!$v['valid']){http_response_code(403);header('Content-Type: application/json');echo json_encode(['error'=>true,'message'=>$v['error'],'code'=>$v['code']]);error_log("[LICENSE_VIOLATION] Code: {$v['code']} | Time: ".date('Y-m-d H:i:s'));exit(1);}$ic=new IntegrityChecker();$iv=$ic->verifyIntegrity();if(!$iv['valid']){http_response_code(403);header('Content-Type: application/json');echo json_encode(['error'=>true,'message'=>$iv['error'],'code'=>$iv['code']]);error_log("[INTEGRITY_VIOLATION] Code: {$iv['code']} | Time: ".date('Y-m-d H:i:s'));exit(1);}if(php_sapi_name()!=='cli'){$_SESSION['license_valid']=true;$_SESSION['license_expires']=$v['expires'];}?>


